import{_ as s,r as o,o as d,c,b as e,e as r,w as i,d as a,a as p,f as t}from"./app-37899220.js";const h="/assets/1-92a18887.png",u="/assets/2-e818dce5.png",f={},_={class:"table-of-contents"},m={href:"https://www.bilibili.com/video/BV1BG4y1p7T6",target:"_blank",rel:"noopener noreferrer"},g=e("iframe",{src:"//player.bilibili.com/player.html?aid=816524122&bvid=BV1BG4y1p7T6&cid=862695941&page=1",scrolling:"no",border:"0",frameborder:"no",framespacing:"0",allowfullscreen:"true"},null,-1),x=t('<h2 id="前言" tabindex="-1"><a class="header-anchor" href="#前言" aria-hidden="true">#</a> 前言</h2><p>之前简单改过一次，就是把apk/res/xml/container_prefs.xml修改一下，这个是偏好设置的布局，加一个EditPreference就行了，但是原有的ListPreference会无法使用（闪退）。所以这次花了点时间写了个dialog，将两者兼容了。</p><h2 id="将此功能添加到apk" tabindex="-1"><a class="header-anchor" href="#将此功能添加到apk" aria-hidden="true">#</a> 将此功能添加到apk</h2><p>推荐使用ED自助补丁一键修改。<br> 如果你掌握apk的基础修改知识，也可以照下方教程手动修改，但本页面提供的文件可能比ED自助补丁要旧。<br> 如果ED自助补丁也用不明白，那么应该去寻找已经修改好的apk直接使用。</p><h3 id="自助修改" tabindex="-1"><a class="header-anchor" href="#自助修改" aria-hidden="true">#</a> 自助修改</h3><p>使用ED自助补丁，用户完全不需要手动编辑smali，只需点一个按钮，等待修改完成后安装新的apk即可。</p>',6),b={href:"https://github.com/ewt45/EDPatch/releases",target:"_blank",rel:"noopener noreferrer"},k={href:"https://www.bilibili.com/video/BV1mY411X7Nn/",target:"_blank",rel:"noopener noreferrer"},v=e("h3",{id:"手动修改",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#手动修改","aria-hidden":"true"},"#"),a(" 手动修改")],-1),E={href:"https://wwn.lanzout.com/iEcpl0dxmyqj",target:"_blank",rel:"noopener noreferrer"},P=t('<ul><li>ContainerSettingFragment这个类是原本就有的，需要先删掉再导入。</li><li>代码里包名是鲁大师，需根据实际情况自行修改。</li><li>如果确保操作无误，修改后依旧闪退，检查apk的arsc/array.xml，有个叫cont_pref_screen_size_values的，第一项应该是default小写的d，如果是大写貌似就会闪退。我懒得改代码了所以请手动改一下arsc吧=-=</li></ul><p>实际上是添加了一个函数和两个成员变量，不过直接导入类更省事点，理论上是通用于ed版的吧。里面用到了两个资源id，一般也不用注意。</p><h2 id="编写思路" tabindex="-1"><a class="header-anchor" href="#编写思路" aria-hidden="true">#</a> 编写思路</h2><h3 id="exa的布局" tabindex="-1"><a class="header-anchor" href="#exa的布局" aria-hidden="true">#</a> exa的布局</h3><p>ex里用的是ContainerSettingsFragment 继承了PreferenceFragmentCompat，设置界面直接从xml创建，而且不用设置id，非常方便。</p><p><img src="'+h+'" alt="图1"></p><p>xml为apk/res/xml/container_prefs.xml，如果想要手动输入分辨率，添加一条EditTextPreference，key是SCREEN_SIZE。但是这样有个问题，就是没法再从list里选了，会闪退。 如果想改一些list中的预设的分辨率，可以去arsc的array里改，虽然dex里GuestContainerConfig类也有那个分辨率的字符串，不过好像只有在复制容器和启动容器的一个通常不会进入的分支里用到，所以不用改。</p><h3 id="自定义preference类" tabindex="-1"><a class="header-anchor" href="#自定义preference类" aria-hidden="true">#</a> 自定义preference类</h3><p>本来想继承ListPreference然后加一项的，结果发现不会改，放弃。</p><h3 id="修改弹出的dialog" tabindex="-1"><a class="header-anchor" href="#修改弹出的dialog" aria-hidden="true">#</a> 修改弹出的dialog</h3><p>发现可以在xml里设置dialogLayout属性，可惜只能加到dialog原有内容的下面，无法替换掉或修改原有内容。</p>',11),y={href:"http://i.lckiss.com/?p=386",target:"_blank",rel:"noopener noreferrer"},w=t('<h2 id="编写代码" tabindex="-1"><a class="header-anchor" href="#编写代码" aria-hidden="true">#</a> 编写代码</h2><p>在fragment里重写onDisplayPreferenceDialog方法。</p><ul><li>设置一个switch开关用于选择是否使用自定义分辨率，开启时无法选择预设分辨率 <ul><li>禁用radiogroup：没法直接禁用，需要给其每个button设置 https://blog.csdn.net/qq_31028313/article/details/90400547</li><li>禁用edittext：我是用的setEnable(false)</li></ul></li><li>声明变量curResolution 记录本次dialog期间最后选择的单选项，用于关闭时写入pref <ul><li>由于需要在监听中调用，监听用到内部类，所以要写成全局变量了</li></ul></li><li>设置监听，点击单选项时，记录所选的对应的值</li><li>点确定关闭dialog时，如果禁用自定义就将记录的值写入，如果开启则先检查宽高是否都填写（开头先选一下单选项）</li><li>初始时从pref读取分辨率，并for循环查找是否为预设分辨率，是则禁用自定义分辨率并选中单选项，如果查到最后一个还不是则启用自定义分辨率并填入宽高（<strong>记得测试一下点开为自定义的情况）</strong></li><li>测试发现summary那里自定义的话没法正常显示了，还得改一下updatePreference()，判断如果是screen_size的话，summary填xml中记录的value</li></ul><p><img src="'+u+`" alt="图2"></p><hr><p>编译成smali之后加到exa的dex中，需要修改：</p><ul><li>lamda不缩写，编译，把三个内部类加上，</li><li>复制那个新的方法onDisplayPreferenceDialog到ContainerSettingsFragment中 <ul><li>包名可能要改成鲁大师</li><li>那两个数组的资源id要改，entries是0x7f030006，values是0x7f030007（同时有个 const/high16要改成const)</li></ul></li><li>开头添加成员变量curResolution和TAG<div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>.field private static final TAG:Ljava/lang/String; = &quot;ContainerSettingsFragment&quot;
.field curResolution:Ljava/lang/String;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div></li><li>替换整个updatePreference方法</li></ul><p>改起来还挺麻烦的，不如改好直接发整个fragment的smali。。。</p><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h2><p>android提供了Preference的Fragment预设界面，只需要编写简单的xml，就可以使用预设的图形化界面进行偏好设置，非常便捷。</p><p>然而如果要修改预设就很麻烦了。。修改ListPreference这种 点击后出现的弹窗界面，有个简单的办法就是在fragment里重写onDisplayPreferenceDialog方法。</p>`,11);function D(C,L){const l=o("router-link"),n=o("ExternalLinkIcon");return d(),c("div",null,[e("nav",_,[e("ul",null,[e("li",null,[r(l,{to:"#前言"},{default:i(()=>[a("前言")]),_:1})]),e("li",null,[r(l,{to:"#将此功能添加到apk"},{default:i(()=>[a("将此功能添加到apk")]),_:1}),e("ul",null,[e("li",null,[r(l,{to:"#自助修改"},{default:i(()=>[a("自助修改")]),_:1})]),e("li",null,[r(l,{to:"#手动修改"},{default:i(()=>[a("手动修改")]),_:1})])])]),e("li",null,[r(l,{to:"#编写思路"},{default:i(()=>[a("编写思路")]),_:1}),e("ul",null,[e("li",null,[r(l,{to:"#exa的布局"},{default:i(()=>[a("exa的布局")]),_:1})]),e("li",null,[r(l,{to:"#自定义preference类"},{default:i(()=>[a("自定义preference类")]),_:1})]),e("li",null,[r(l,{to:"#修改弹出的dialog"},{default:i(()=>[a("修改弹出的dialog")]),_:1})])])]),e("li",null,[r(l,{to:"#编写代码"},{default:i(()=>[a("编写代码")]),_:1})]),e("li",null,[r(l,{to:"#总结"},{default:i(()=>[a("总结")]),_:1})])])]),e("p",null,[a("视频演示： "),e("a",m,[a("【安卓Exagear】添加自定义分辨率功能，同时保证原预设分辨率可正常选择"),r(n)])]),g,x,e("p",null,[e("a",b,[a("下载地址"),r(n)])]),e("p",null,[e("a",k,[a("视频介绍"),r(n)])]),p(" :::warning\n以下的修改示例代码，包名使用鲁大师包名`Lcom/ludashi/benchmark/`，请注意根据实际情况自行调整。\n::: "),v,e("p",null,[a("先提供一下"),e("a",E,[a("现成smali代码"),r(n)]),a("，用mt管理器的dex编辑器++功能，长按任意包名导入zip即可。 注意：")]),P,e("p",null,[a("在搜如何自定义dialogPreference时搜到了这个 "),e("a",y,[a("自定义DialogPreference"),r(n)]),a("，发现如果要修改点击偏好选项弹出的弹窗的内容，其实在onDisplayPreferenceDialog里劫持一下然后自定义显示一个dialog就行了。。。虽然不太好，但是简单（")]),w])}const B=s(f,[["render",D],["__file","index.html.vue"]]);export{B as default};
